// Separar clips por plataforma
const clips = $input.all().map(i => i.json);

// Se veio como array dentro de um item
const allClips = Array.isArray(clips[0]) ? clips[0] : clips;

const youtube = allClips.filter(c => c.platform === 'shorts');
const tiktok = allClips.filter(c => c.platform === 'tiktok');
const instagram = allClips.filter(c => c.platform === 'reels');

// Extrair video IDs do YouTube
const ytIds = youtube.map(c => {
  const match = c.videoUrl.match(/shorts\/([a-zA-Z0-9_-]+)/) || c.videoUrl.match(/youtu\.be\/([a-zA-Z0-9_-]+)/);
  return { clipId: c.id, videoId: match ? match[1] : null, handle: c.handle };
}).filter(v => v.videoId);

// Agrupar YouTube IDs em batches de 50
const ytBatches = [];
for (let i = 0; i < ytIds.length; i += 50) {
  ytBatches.push(ytIds.slice(i, i + 50));
}

return [{
  json: {
    ytBatches,
    ytClipMap: ytIds,
    manualUpdate: {
      tiktok: tiktok.map(c => ({ id: c.id, url: c.videoUrl, handle: c.handle })),
      instagram: instagram.map(c => ({ id: c.id, url: c.videoUrl, handle: c.handle }))
    },
    totalClips: allClips.length,
    youtubeCount: youtube.length,
    tiktokCount: tiktok.length,
    instagramCount: instagram.length
  }
}];

// Pegar o primeiro batch de IDs do YouTube
const data = $input.first().json;
const batches = data.ytBatches;

if (!batches || batches.length === 0) return [];

// Retornar cada batch como um item separado
return batches.map(batch => ({
  json: {
    videoIds: batch.map(b => b.videoId).join(','),
    batchItems: batch,
    clipMap: data.ytClipMap,
    manualUpdate: data.manualUpdate,
    totalClips: data.totalClips
  }
}));

// Mapear views do YouTube de volta para clip IDs
const ytResponse = $input.first().json;
const items = ytResponse.items || [];

// Buscar clipMap do node anterior via $('Preparar Batches YouTube')
const prepNode = $('Preparar Batches YouTube').first().json;
const clipMap = prepNode.clipMap;
const manualUpdate = prepNode.manualUpdate;

const updates = [];

items.forEach(item => {
  const videoId = item.id;
  const views = parseInt(item.statistics.viewCount, 10);

  // Encontrar o clip correspondente
  const mapping = clipMap.find(m => m.videoId === videoId);
  if (mapping) {
    updates.push({ id: mapping.clipId, views });
  }
});

return [{
  json: {
    updates,
    manualUpdate,
    youtubeUpdated: updates.length,
    totalClips: prepNode.totalClips
  }
}];

// Gerar resumo para notificação
const mapNode = $('Mapear Views YouTube').first().json;
const bulkResult = $input.first().json;

const manual = mapNode.manualUpdate || { tiktok: [], instagram: [] };
const now = new Date().toISOString().split('T')[0];

let summary = `📊 **ClipCash - Resumo Diário (${now})**\n\n`;
summary += `✅ YouTube atualizado: ${mapNode.youtubeUpdated} clips\n`;
summary += `📱 TikTok (manual): ${manual.tiktok.length} clips\n`;
summary += `📸 Instagram (manual): ${manual.instagram.length} clips\n`;
summary += `📈 Total de clips: ${mapNode.totalClips}\n`;

if (manual.tiktok.length > 0) {
  summary += `\n**TikTok - Atualizar manualmente:**\n`;
  manual.tiktok.forEach(c => {
    summary += `- ${c.handle}: ${c.url}\n`;
  });
}

if (manual.instagram.length > 0) {
  summary += `\n**Instagram - Atualizar manualmente:**\n`;
  manual.instagram.forEach(c => {
    summary += `- ${c.handle}: ${c.url}\n`;
  });
}

// Dados para Google Sheets
const sheetRows = (mapNode.updates || []).map(u => ({
  date: now,
  clipId: u.id,
  platform: 'youtube',
  views: u.views
}));

return [{
  json: {
    summary,
    sheetRows,
    discordContent: summary
  }
}];

// Sem clips YouTube - pular direto pro resumo
const data = $input.first().json;
const manual = data.manualUpdate || { tiktok: [], instagram: [] };
const now = new Date().toISOString().split('T')[0];

let summary = `📊 **ClipCash - Resumo Diário (${now})**\n\n`;
summary += `⚠️ Nenhum clip YouTube para atualizar\n`;
summary += `📱 TikTok (manual): ${manual.tiktok.length} clips\n`;
summary += `📸 Instagram (manual): ${manual.instagram.length} clips\n`;
summary += `📈 Total de clips: ${data.totalClips}\n`;

if (manual.tiktok.length > 0) {
  summary += `\n**TikTok - Atualizar manualmente:**\n`;
  manual.tiktok.forEach(c => {
    summary += `- ${c.handle}: ${c.url}\n`;
  });
}

if (manual.instagram.length > 0) {
  summary += `\n**Instagram - Atualizar manualmente:**\n`;
  manual.instagram.forEach(c => {
    summary += `- ${c.handle}: ${c.url}\n`;
  });
}

return [{
  json: {
    summary,
    sheetRows: [],
    discordContent: summary
  }
}];
